/*
  # Add missing and new email templates

  ## Purpose
  Insert all missing email templates that the system requires but are not yet in the database.
  Also adds new templates for:
  - booking_cancelled
  - pickup_reminder
  - review_request
  - company_approved
  - company_rejected
  - company_suspended
  - special_offer (new - for promotional emails to clients)
  - inactive_client_reminder (new - for clients who registered but haven't booked)
  - payment_received (new - payment confirmation)
  - subscription_expiring (new - company subscription expiry warning)
  - subscription_expired (new - company subscription expired)

  ## Changes
  - Inserts templates only if they don't already exist (ON CONFLICT DO NOTHING)
  - All templates in Albanian language
  - Professional HTML styling with brand colors
*/

INSERT INTO email_templates (template_key, subject_template, html_template, text_template, description, is_active)
VALUES

-- booking_cancelled
('booking_cancelled',
'Rezervimi juaj u anulua - {{vehicleName}}',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Rezervim i Anuluar</title></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#1a1a2e 0%,#16213e 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><img src="https://images.pexels.com/photos/170811/pexels-photo-170811.jpeg?auto=compress&cs=tinysrgb&w=60&h=30&fit=crop" alt="" style="display:none"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Rezervimi u Anulua</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#fef3c7;border:1px solid #fde68a;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#92400e;font-size:14px;font-weight:600;margin:0">Rezervimi juaj u anulua me sukses</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Rezervimi juaj per automjetin <strong>{{vehicleName}}</strong> u anulua me date {{cancelDate}}.</p><table width="100%" style="background:#f9fafb;border-radius:12px;padding:20px;margin-bottom:24px" cellpadding="0" cellspacing="0"><tr><td style="padding:8px 0;border-bottom:1px solid #e5e7eb"><span style="color:#6b7280;font-size:13px">Automjeti:</span></td><td style="padding:8px 0;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="color:#111827;font-size:13px">{{vehicleName}}</strong></td></tr><tr><td style="padding:8px 0"><span style="color:#6b7280;font-size:13px">Data e anulimit:</span></td><td style="padding:8px 0;text-align:right"><strong style="color:#111827;font-size:13px">{{cancelDate}}</strong></td></tr></table><div style="text-align:center;margin-bottom:24px"><a href="{{searchUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Kërko Automjete të Tjera</a></div><p style="color:#6b7280;font-size:12px;text-align:center;margin:0">Nese keni pyetje, kontaktoni ekipin tone ne info@rentakar.com</p></td></tr></table></td></tr></table></body></html>',
'Rezervimi juaj per {{vehicleName}} u anulua me date {{cancelDate}}. Vizitoni {{searchUrl}} per te kerkuar automjete te tjera.',
'Template per anulimin e rezervimit - dergohet klientit',
true),

-- pickup_reminder
('pickup_reminder',
'Kujtese: Nesër merrni {{vehicleName}}!',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Nesër Merrni Automjetin</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#ecfdf5;border:1px solid #a7f3d0;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#065f46;font-size:15px;font-weight:700;margin:0">Rezervimi juaj fillon nesër!</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Kjo eshte nje kujtese qe neser, me date <strong>{{pickupDate}}</strong> ne oren <strong>{{pickupTime}}</strong>, eshte planifikuar marrja e automjetit tuaj.</p><table width="100%" style="background:#f9fafb;border-radius:12px;padding:20px;margin-bottom:24px" cellpadding="0" cellspacing="0"><tr><td style="padding:8px 0;border-bottom:1px solid #e5e7eb"><span style="color:#6b7280;font-size:13px">Automjeti:</span></td><td style="padding:8px 0;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="color:#111827;font-size:13px">{{vehicleName}}</strong></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #e5e7eb"><span style="color:#6b7280;font-size:13px">Kompania:</span></td><td style="padding:8px 0;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="color:#111827;font-size:13px">{{companyName}}</strong></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #e5e7eb"><span style="color:#6b7280;font-size:13px">Telefoni i kompanise:</span></td><td style="padding:8px 0;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="color:#111827;font-size:13px">{{companyPhone}}</strong></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #e5e7eb"><span style="color:#6b7280;font-size:13px">Vendmarrja:</span></td><td style="padding:8px 0;border-bottom:1px solid #e5e7eb;text-align:right"><strong style="color:#111827;font-size:13px">{{pickupLocation}}</strong></td></tr><tr><td style="padding:8px 0"><span style="color:#6b7280;font-size:13px">Depozita:</span></td><td style="padding:8px 0;text-align:right"><strong style="color:#f59e0b;font-size:13px">{{deposit}} EUR</strong></td></tr></table><div style="background:#fffbeb;border:1px solid #fde68a;border-radius:10px;padding:16px;margin-bottom:24px"><p style="color:#92400e;font-size:13px;font-weight:600;margin:0 0 6px">Keni me vete:</p><ul style="color:#78350f;font-size:13px;margin:0;padding-left:20px"><li>Leternjoftimi ose pasaporta</li><li>Patenten e shoferit</li><li>Kartelen e pagesave (nese eshte rene dakord)</li></ul></div><div style="text-align:center;margin-bottom:16px"><a href="{{dashboardUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Shiko Rezervimin</a></div></td></tr></table></td></tr></table></body></html>',
'Kujtese: Neser merrni {{vehicleName}} nga {{companyName}}. Vendmarrja: {{pickupLocation}}, ora {{pickupTime}}.',
'Template per kujtesen 24 ore para marrjes se automjetit',
true),

-- review_request
('review_request',
'Si ishte eksperienca? Lini vlerësimin tuaj!',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Si Ishte Eksperienca?</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 24px">Shpresojme qe eksperienca juaj me automjetin <strong>{{vehicleName}}</strong> ishte e mrekullueshme. Mendimi juaj eshte shume i rendesishem per ne dhe per klientet e tjere.</p><div style="text-align:center;margin:32px 0"><div style="font-size:40px;margin-bottom:16px">&#11088;</div><p style="color:#374151;font-size:16px;font-weight:700;margin:0 0 20px">Lini vleresimin tuaj tani!</p><a href="{{reviewUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:16px 32px;border-radius:12px">Vlereso Sherbimin</a></div><p style="color:#9ca3af;font-size:12px;text-align:center;margin:24px 0 0">Vleresimi juaj ndihmon kompanite te permiresojne sherbimet dhe klientet te bejne zgjedhje me te mira.</p></td></tr></table></td></tr></table></body></html>',
'Pershendetje {{clientName}}, si ishte eksperienca juaj me {{vehicleName}}? Leni vleresimin ne: {{reviewUrl}}',
'Template per kerkesen e vleresimit pas perfundimit te rezervimit',
true),

-- company_approved
('company_approved',
'Urime! Kompania juaj u aprovua - RentaKar',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Kompania u Aprovua!</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#ecfdf5;border:1px solid #6ee7b7;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><div style="font-size:40px;margin-bottom:8px">&#9989;</div><p style="color:#065f46;font-size:16px;font-weight:700;margin:0">Kompania juaj eshte aktive!</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{companyName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Me kenaqesi ju njoftojme qe kompania juaj u aprovua nga ekipi i RentaKar. Tani mund te filloni te shtoni automjetet tuaja dhe te merrni rezervime.</p><div style="background:#f9fafb;border-radius:12px;padding:20px;margin-bottom:24px"><h3 style="color:#111827;font-size:14px;font-weight:700;margin:0 0 12px">Hapat e ardhshem:</h3><p style="color:#6b7280;font-size:13px;margin:0 0 8px">1. Hyni ne dashboard-in e kompanise</p><p style="color:#6b7280;font-size:13px;margin:0 0 8px">2. Shtoni automjetet tuaja me foto dhe cmime</p><p style="color:#6b7280;font-size:13px;margin:0 0 8px">3. Klientet do te fillojne te bejne rezervime</p><p style="color:#6b7280;font-size:13px;margin:0">4. Menaxhoni rezervimet dhe pagesat ne dashboard</p></div><div style="text-align:center;margin-bottom:24px"><a href="{{dashboardUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Hap Dashboard-in</a></div><p style="color:#6b7280;font-size:12px;text-align:center">Per mbeshtetje: {{supportEmail}} | {{supportPhone}}</p></td></tr></table></td></tr></table></body></html>',
'Urime {{companyName}}! Kompania juaj u aprovua. Hyni ne dashboard: {{dashboardUrl}}',
'Template per aprovimin e kompanise nga admin',
true),

-- company_rejected
('company_rejected',
'Update mbi aplikimin tuaj - RentaKar',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Update mbi Aplikimin</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{companyName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Pas shqyrtimit te aplikimit tuaj, ekipi yne nuk mundi ta aprovoje per momentin.</p><div style="background:#fef2f2;border:1px solid #fecaca;border-radius:12px;padding:16px;margin-bottom:24px"><p style="color:#991b1b;font-size:13px;font-weight:600;margin:0 0 6px">Arsyeja:</p><p style="color:#7f1d1d;font-size:13px;margin:0">{{rejectionReason}}</p></div><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 24px">Nese mendoni se ky vendim eshte gabim ose keni pyetje, ju lutem kontaktoni ekipin tone.</p><p style="color:#6b7280;font-size:12px;text-align:center">Per mbeshtetje: {{supportEmail}} | {{supportPhone}}</p></td></tr></table></td></tr></table></body></html>',
'Pershendetje {{companyName}}, aplikimi juaj nuk u aprovua. Arsyeja: {{rejectionReason}}. Kontaktoni: {{supportEmail}}',
'Template per refuzimin e kompanise nga admin',
true),

-- company_suspended
('company_suspended',
'Llogaria juaj u pezullua - RentaKar',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Llogaria u Pezullua</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#fef3c7;border:1px solid #fde68a;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#92400e;font-size:15px;font-weight:700;margin:0">Llogaria juaj eshte pezulluar</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{companyName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Llogaria juaj ne RentaKar eshte pezulluar per arsyen e meposhtme:</p><div style="background:#fef3c7;border:1px solid #fde68a;border-radius:12px;padding:16px;margin-bottom:24px"><p style="color:#92400e;font-size:13px;margin:0">{{suspensionReason}}</p></div><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 24px">Gjate periudhes se pezullimit, automjetet tuaja nuk do te jene te dukshme per klientet dhe rezervimet e reja do te bllokohen. Per te rifituar qasjen, ju lutem kontaktoni ekipin tone.</p><p style="color:#6b7280;font-size:12px;text-align:center">Per mbeshtetje: {{supportEmail}} | {{supportPhone}}</p></td></tr></table></td></tr></table></body></html>',
'Llogaria e {{companyName}} u pezullua. Arsyeja: {{suspensionReason}}. Kontaktoni: {{supportEmail}}',
'Template per pezullimin e kompanise nga admin',
true),

-- special_offer (new)
('special_offer',
'Oferte speciale per ju - {{offerTitle}}',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#b45309 0%,#d97706 50%,#f59e0b 100%);padding:40px 32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:rgba(255,255,255,0.85);font-size:12px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><div style="font-size:48px;margin-bottom:12px">&#127381;</div><h1 style="color:#ffffff;font-size:28px;font-weight:800;margin:0 0 8px">{{offerTitle}}</h1><p style="color:rgba(255,255,255,0.9);font-size:16px;margin:0">Oferte ekskluzive per ju!</p></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 24px">{{offerDescription}}</p><div style="background:linear-gradient(135deg,#fffbeb,#fef3c7);border:2px solid #f59e0b;border-radius:16px;padding:24px;margin-bottom:28px;text-align:center"><p style="color:#92400e;font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:2px;margin:0 0 8px">Zbritja juaj</p><p style="color:#d97706;font-size:48px;font-weight:900;margin:0 0 4px">{{discountPercent}}%</p><p style="color:#78350f;font-size:13px;margin:0 0 12px">Vlefshme deri me {{validUntil}}</p><div style="background:#ffffff;border:2px dashed #d97706;border-radius:8px;padding:12px"><p style="color:#92400e;font-size:12px;font-weight:600;margin:0 0 4px">Kodi i zbritjes:</p><p style="color:#d97706;font-size:20px;font-weight:900;letter-spacing:3px;margin:0">{{promoCode}}</p></div></div><div style="text-align:center;margin-bottom:28px"><a href="{{searchUrl}}" style="display:inline-block;background:linear-gradient(135deg,#d97706,#b45309);color:#ffffff;font-size:15px;font-weight:700;text-decoration:none;padding:16px 36px;border-radius:12px">Shfleto Automjetet</a></div><p style="color:#9ca3af;font-size:11px;text-align:center;margin:0">Oferta eshte e kufizuar dhe nuk mund te kombinohet me zbritje te tjera.</p></td></tr></table></td></tr></table></body></html>',
'Oferte speciale {{offerTitle}} - {{discountPercent}}% zbritje! Kodi: {{promoCode}}. Vlefshme deri: {{validUntil}}. Vizitoni: {{searchUrl}}',
'Template per ofertat speciale dhe promocionet - dergohet klienteve',
true),

-- inactive_client_reminder (new)
('inactive_client_reminder',
'Ju mungoni! Zbuloni automjetet tona te reja',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);padding:40px 32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#f59e0b;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><div style="font-size:40px;margin-bottom:12px">&#128663;</div><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Ju Kemi Humbur!</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Ka nje kohe qe nuk ju kemi pare ne RentaKar. Kemi sjelle automjete te reja me cmime te vecanta qe mendojme do t''u pelqejne.</p><div style="background:#f9fafb;border-radius:12px;padding:20px;margin-bottom:24px"><h3 style="color:#111827;font-size:14px;font-weight:700;margin:0 0 12px">Pse te zgjidhni RentaKar?</h3><p style="color:#6b7280;font-size:13px;margin:0 0 8px">&#10003; Mbi 500 automjete ne te gjitha qytetet</p><p style="color:#6b7280;font-size:13px;margin:0 0 8px">&#10003; Cmime te perballueshme dhe transparente</p><p style="color:#6b7280;font-size:13px;margin:0 0 8px">&#10003; Anulim falas deri 48 ore para marrjes</p><p style="color:#6b7280;font-size:13px;margin:0">&#10003; Kompani te verifikuara dhe te besueshme</p></div><div style="text-align:center;margin-bottom:28px"><a href="{{searchUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:16px 32px;border-radius:12px">Shfleto Automjetet</a></div><p style="color:#9ca3af;font-size:11px;text-align:center;margin:0">Nese nuk doni me te merrni emaile nga ne, mund te cregjistroheni ne cdo kohe.</p></td></tr></table></td></tr></table></body></html>',
'Pershendetje {{clientName}}, ju mungoni! Vizitoni RentaKar per automjete te reja: {{searchUrl}}',
'Template per klientet e regjistruar qe nuk kane bere rezervime ose jane joaktive',
true),

-- payment_received (new)
('payment_received',
'Pagesa u konfirmua - {{vehicleName}}',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#064e3b 0%,#065f46 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#6ee7b7;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><div style="font-size:40px;margin-bottom:8px">&#9989;</div><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Pagesa u Konfirmua</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{clientName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Pagesa juaj per rezervimin e automjetit <strong>{{vehicleName}}</strong> u konfirmua me sukses.</p><table width="100%" style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;padding:20px;margin-bottom:24px" cellpadding="0" cellspacing="0"><tr><td style="padding:8px 0;border-bottom:1px solid #dcfce7"><span style="color:#166534;font-size:13px">Automjeti:</span></td><td style="padding:8px 0;border-bottom:1px solid #dcfce7;text-align:right"><strong style="color:#14532d;font-size:13px">{{vehicleName}}</strong></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #dcfce7"><span style="color:#166534;font-size:13px">Shuma:</span></td><td style="padding:8px 0;border-bottom:1px solid #dcfce7;text-align:right"><strong style="color:#15803d;font-size:16px">{{amount}} EUR</strong></td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #dcfce7"><span style="color:#166534;font-size:13px">Metoda:</span></td><td style="padding:8px 0;border-bottom:1px solid #dcfce7;text-align:right"><strong style="color:#14532d;font-size:13px">{{paymentMethod}}</strong></td></tr><tr><td style="padding:8px 0"><span style="color:#166534;font-size:13px">Data:</span></td><td style="padding:8px 0;text-align:right"><strong style="color:#14532d;font-size:13px">{{paymentDate}}</strong></td></tr></table><div style="text-align:center"><a href="{{dashboardUrl}}" style="display:inline-block;background:linear-gradient(135deg,#16a34a,#15803d);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Shiko Rezervimin</a></div></td></tr></table></td></tr></table></body></html>',
'Pagesa per {{vehicleName}} u konfirmua. Shuma: {{amount}} EUR. Metoda: {{paymentMethod}}. Shiko: {{dashboardUrl}}',
'Template per konfirmimin e pagesës',
true),

-- subscription_expiring (new)
('subscription_expiring',
'Abonimi juaj skadон në {{daysLeft}} ditë - Rinovojeni tani',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#7c2d12 0%,#b45309 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#fed7aa;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><div style="font-size:40px;margin-bottom:8px">&#9203;</div><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Abonimi Skadon Se Shpejti</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#fffbeb;border:2px solid #f59e0b;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#92400e;font-size:24px;font-weight:900;margin:0 0 4px">{{daysLeft}} Dite</p><p style="color:#78350f;font-size:13px;margin:0">mbeten deri ne skadim</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{companyName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Abonimi juaj <strong>{{planName}}</strong> skadon me date <strong>{{expiryDate}}</strong>. Per te vazhduar te merrni rezervime, rinovojeni abonimin tani.</p><div style="background:#fef3c7;border-radius:10px;padding:16px;margin-bottom:24px"><p style="color:#92400e;font-size:13px;margin:0">Nese abonimi skadon, automjetet tuaja do te fshihen nga rezultatet e kerkimit dhe nuk do te mund te merrni rezervime te reja.</p></div><div style="text-align:center"><a href="{{dashboardUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Rinovo Abonimin</a></div></td></tr></table></td></tr></table></body></html>',
'Abonimi i {{companyName}} skadon ne {{daysLeft}} dite ({{expiryDate}}). Rinovojeni ne: {{dashboardUrl}}',
'Template per paralajmerimin e skadimit te abonimit te kompanise',
true),

-- subscription_expired (new)
('subscription_expired',
'Abonimi juaj skadoi - Riaktivizoni llogarinë',
'<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f5f5;padding:32px 16px"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%"><tr><td style="background:linear-gradient(135deg,#1f2937 0%,#374151 100%);padding:32px;border-radius:16px 16px 0 0;text-align:center"><p style="color:#9ca3af;font-size:14px;font-weight:700;letter-spacing:3px;text-transform:uppercase;margin:0 0 8px">RENTAKAR</p><div style="font-size:40px;margin-bottom:8px">&#128721;</div><h1 style="color:#ffffff;font-size:24px;font-weight:800;margin:0">Abonimi Skadoi</h1></td></tr><tr><td style="background:#ffffff;padding:32px;border-radius:0 0 16px 16px"><div style="background:#fef2f2;border:1px solid #fecaca;border-radius:12px;padding:20px;margin-bottom:24px;text-align:center"><p style="color:#991b1b;font-size:15px;font-weight:700;margin:0">Llogaria juaj eshte joaktive</p></div><p style="color:#374151;font-size:15px;margin:0 0 20px">Pershendetje <strong>{{companyName}}</strong>,</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 20px">Abonimi juaj <strong>{{planName}}</strong> skadoi me date <strong>{{expiryDate}}</strong>. Aktualisht, automjetet tuaja nuk jane te dukshme per klientet.</p><p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0 0 24px">Per te riaktivizuar llogarinë tuaj dhe filluar rishtas te merrni rezervime, zgjidhni nje plan te ri.</p><div style="text-align:center;margin-bottom:24px"><a href="{{dashboardUrl}}" style="display:inline-block;background:linear-gradient(135deg,#f59e0b,#d97706);color:#ffffff;font-size:14px;font-weight:700;text-decoration:none;padding:14px 28px;border-radius:12px">Riaktiviyo Llogarinë</a></div><p style="color:#6b7280;font-size:12px;text-align:center">Per mbeshtetje: {{supportEmail}} | {{supportPhone}}</p></td></tr></table></td></tr></table></body></html>',
'Abonimi i {{companyName}} skadoi ({{expiryDate}}). Riaktivizoni ne: {{dashboardUrl}}',
'Template per njoftimin e skadimit te abonimit te kompanise',
true)

ON CONFLICT (template_key) DO NOTHING;
